// Solution
function fixCss(cssString) {
  let lines = cssString.split('\n');
  for (let line of lines) {
    if (line.includes(':before') || line.includes(':after')) {
      let prop = line.split(':')[0].trim();
      if (prop === 'width' || prop === 'height') {
        line = line.replace(prop, prop + ' box-sizing: border-box');
      }
    }
  }
  return lines.join('\n');
}

