class Solution:
  def fix_css(self, css_string):
    lines = css_string.split('\n');
    for line in lines:
      if line.startswith('::before') or line.startswith('::after'):
        prop = line.split(':')[0].strip();
        if prop in ['width', 'height']:
          line = line.replace(prop, prop + ' box-sizing: border-box');
    return '\n'.join(lines);
